sys_script.script:
(function executeRule(current, previous) {
    var decision = current.getValue("agent_decision");

    if (decision === "approve") {
        current.setValue("state", "3"); // Resolved - triggers fulfillment flow
    } else if (decision === "deny") {
        current.setValue("state", "4"); // Closed - triggers denied notification flow
    } else if (decision === "escalate") {
        current.setValue("state", "-5"); // Pending - on hold for human review
    }
})(current, previous);
